#!/bin/bash
# A script to patch runner.rs to support the auto mode user agent delegation.
perl -0777 -pi -e 's|            if !_autonomous_mode \{ break; \}\n            if loop_count >= TEAM_A2A_AUTONOMOUS_MAX_CONTINUES \{|            let mut is_input_required = false;\n            if let Ok(last_event) = serde_json::from_str::<serde_json::Value>(buffer.lines().last().unwrap_or_default().trim_start_matches("data: ")) {\n                let state = last_event.pointer("/status/state").and_then(|v| v.as_str()).unwrap_or("");\n                is_input_required = state == "input-required" || state == "TASK_STATE_INPUT_REQUIRED";\n            }\n            if !_autonomous_mode \{ break; \}\n            if loop_count >= TEAM_A2A_AUTONOMOUS_MAX_CONTINUES \{|;' src/team_orchestration/runner.rs
